// File: UploadLogsWorker.kt
import android.content.Context
import androidx.hilt.work.HiltWorker
import androidx.work.*
import dagger.assisted.Assisted
import dagger.assisted.AssistedInject

// 1. The Worker itself — CoroutineWorker for suspend fn work
@HiltWorker
class UploadLogsWorker @AssistedInject constructor(
  @Assisted appContext: Context,
  @Assisted params: WorkerParameters,
  private val logRepo: LogRepository,          // Hilt injects
) : CoroutineWorker(appContext, params) {

  override suspend fun doWork(): Result = try {
    logRepo.uploadPendingLogs()
    Result.success(workDataOf("count" to logRepo.uploadedCount))
  } catch (e: java.io.IOException) {
    if (runAttemptCount < 3) Result.retry() else Result.failure()
  } catch (e: Exception) {
    Result.failure(workDataOf("error" to e.message))
  }
}

// 2. Scheduling — from your Application.onCreate() or first login
fun scheduleLogUpload(context: Context) {
  val constraints = Constraints.Builder()
    .setRequiredNetworkType(NetworkType.UNMETERED)   // Wi-Fi only — respects user data
    .setRequiresBatteryNotLow(true)
    .build()

  val request = PeriodicWorkRequestBuilder<UploadLogsWorker>(
      repeatInterval = 6, java.util.concurrent.TimeUnit.HOURS)
    .setConstraints(constraints)
    .setBackoffCriteria(BackoffPolicy.EXPONENTIAL, 30, java.util.concurrent.TimeUnit.SECONDS)
    .build()

  // ENQUEUE_UNIQUE ensures we don't schedule duplicates on every launch
  WorkManager.getInstance(context).enqueueUniquePeriodicWork(
    "log_upload",
    ExistingPeriodicWorkPolicy.KEEP,
    request,
  )
}

// 3. Chained work — compress THEN upload
fun compressAndUpload(context: Context) {
  val compress = OneTimeWorkRequestBuilder<CompressWorker>()
    .setInputData(workDataOf("path" to "/sdcard/big.mov"))
    .build()

  val upload = OneTimeWorkRequestBuilder<UploadWorker>()
    // upload receives compress's output data as its input automatically
    .setConstraints(Constraints.Builder().setRequiredNetworkType(NetworkType.UNMETERED).build())
    .build()

  WorkManager.getInstance(context)
    .beginWith(compress)      // step 1
    .then(upload)             // step 2 — runs only if compress succeeded
    .enqueue()
}

